const item = $input.first().json;
const raw = item.output || item.text || item.response || item.message || '{}';
const cleaned = String(raw).trim().replace(/^```json\s*/i, '').replace(/^```/, '').replace(/```$/, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  parsed = {
    account_name: item.account_name || item.accountName || item.recordSummary || 'Unknown Account',
    confidence: 'low',
    estimated_amount: item.estimated_amount || 0,
    signal_summary: cleaned || 'No structured analysis returned.',
    evidence: [],
    recommended_action: 'Review the source record manually.',
    should_alert: false,
    owner_name: item.owner || item.accountOwner || ''
  };
}
const confidence = ['high', 'medium', 'low'].includes(String(parsed.confidence || '').toLowerCase())
  ? String(parsed.confidence).toLowerCase()
  : 'medium';
const estimatedAmount = Number(parsed.estimated_amount || parsed.estimatedAmount || item.amount || 0) || 0;
return [{
  json: {
    ...item,
    account_name: parsed.account_name || item.account_name || item.accountName || 'Unknown Account',
    owner_name: parsed.owner_name || item.owner || item.accountOwner || '',
    confidence,
    estimated_amount: estimatedAmount,
    signal_summary: parsed.signal_summary || 'No signal summary returned.',
    evidence: Array.isArray(parsed.evidence) ? parsed.evidence : [],
    recommended_action: parsed.recommended_action || 'Review the opportunity manually.',
    should_alert: parsed.should_alert !== false,
    analysis_json: parsed
  }
}];

const items = $input.all().map((entry) => entry.json);
const alertItems = items.filter((item) => item.should_alert);
const config = items[0] || {};
const rank = { high: 0, medium: 1, low: 2 };
alertItems.sort((left, right) => (rank[left.confidence] ?? 3) - (rank[right.confidence] ?? 3) || (right.estimated_amount || 0) - (left.estimated_amount || 0));
const buckets = { high: [], medium: [], low: [] };
for (const item of alertItems) {
  const bucket = buckets[item.confidence] || buckets.medium;
  bucket.push(item);
}
const formatCurrency = (value) => {
  const numeric = Number(value || 0);
  return numeric > 0 ? `$${numeric.toLocaleString()}` : 'Amount TBD';
};
const sectionOrder = [
  ['high', '🟢 High Confidence'],
  ['medium', '🟡 Medium Confidence'],
  ['low', '⚪ Watch List']
];
const sections = [];
for (const [key, label] of sectionOrder) {
  const entries = buckets[key];
  if (!entries.length) continue;
  const lines = entries.flatMap((item) => {
    const evidence = item.evidence.slice(0, 2).map((line) => `- ${line}`);
    return [
      `• *${item.account_name}* | ${formatCurrency(item.estimated_amount)} | ${item.owner_name || 'Owner TBD'}`,
      `  ${item.signal_summary}`,
      ...evidence.map((line) => `  ${line}`),
      `  👉 ${item.recommended_action}`,
    ];
  });
  sections.push([`*${label}*`, ...lines].join('\n'));
}
const reportDate = new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
const headline = alertItems.length
  ? `🔍 *Weekly Opportunity Discovery* — ${alertItems.length} hidden opportunities found`
  : '🔍 *Weekly Opportunity Discovery* — no qualifying hidden opportunities this week';
const slackBody = [headline, reportDate, '', ...(sections.length ? sections : ['No accounts cleared the confidence threshold this run.']), '', '_Powered by Backstory MCP — deterministic delivery_'].join('\n');
const htmlSections = sections.length
  ? sections.map((section) => `<pre>${section.replace(/[&<>]/g, (char) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;' }[char]))}</pre>`).join('')
  : '<p>No accounts cleared the confidence threshold this run.</p>';
const htmlEmail = `<h2>Weekly Opportunity Discovery</h2><p>${reportDate}</p>${htmlSections}<p><em>Powered by Backstory MCP — deterministic delivery</em></p>`;
return [{ json: {
  workflow_id: '04-opportunity-discovery',
  workflow_name: 'Opportunity Discovery',
  delivery_channel_id: config.default_channel_id || '',
  summary_email: config.summary_email || '',
  from_email: config.from_email || 'success@backstory.ai',
  slack_body: slackBody,
  email_subject: `Weekly Opportunity Discovery — ${alertItems.length} account${alertItems.length === 1 ? '' : 's'} to review`,
  html_email: htmlEmail,
  plain_text: slackBody,
  opportunity_count: alertItems.length
} }];
